import{_ as a}from"./chunks/demo-main.zRXlsRu9.js";import{c as s,Q as i,j as c,m as t}from"./chunks/framework.BkjtU8k0.js";const m=JSON.parse('{"title":"Flyfish Viewer","titleTemplate":false,"description":"","frontmatter":{"layout":"page","title":"Flyfish Viewer","titleTemplate":false},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1779174204000}'),r={name:"index.md"};function o(d,e,n,l,p,h){return i(),c("div",null,[...e[0]||(e[0]=[t('<main class="doc-home"><section class="doc-home-hero"><div class="doc-home-hero-inner"><div class="doc-eyebrow">Official Docs And Component Home</div><h1>Flyfish Viewer</h1><p> 纯前端多格式文件预览组件。把 Word、Excel、PPT、PDF、OFD、CAD、Markdown、代码、图片和视频预览能力放进浏览器端， 同时提供 Vue3、Vue2.7 和 iframe 三种集成路径。 </p><div class="doc-home-actions"><a class="doc-action doc-action-primary" href="/guide/quickstart">快速开始</a><a class="doc-action" href="https://viewer.flyfish.dev" target="_blank" rel="noreferrer">在线 Demo</a><a class="doc-action" href="https://github.com/flyfish-dev/file-viewer" target="_blank" rel="noreferrer">GitHub 成品</a></div></div></section><section class="doc-home-metrics" aria-label="Flyfish Viewer 核心指标"><div><strong>59</strong><span>个扩展名映射</span></div><div><strong>11</strong><span>条预览链路</span></div><div><strong>Vue2/3</strong><span>双包线同步维护</span></div><div><strong>Iframe</strong><span>支持多系统复用</span></div></section><section class="doc-section"><div class="doc-section-heading"><span>Product Experience</span><h2>产品化的文件预览，而不是格式清单</h2><p> 文档解析、阅读布局、示例验收和分发交付被放在同一条链路里维护。接入前可以先看真实 Demo， 接入后也能通过 npm、静态站或 iframe 继续迭代。 </p></div><div class="doc-showcase"><figure><img src="'+a+'" alt="Flyfish Viewer 在线预览器主界面"><figcaption>在线 Demo 包含示例文件选择器、上传入口和多格式预览区，可直接用于验收真实浏览体验。</figcaption></figure><div class="doc-showcase-list"><article><span>01</span><h3>打开即适配阅读宽度</h3><p>PDF 和 Word 会按当前视口计算默认缩放，导航窗格开启时也尽量保留可读区域。</p></article><article><span>02</span><h3>重型能力按需进入</h3><p>OFD、CAD、PDF、Office、Markdown 和代码高亮都拆成异步块，命中格式时再加载。</p></article><article><span>03</span><h3>示例覆盖完整验收路径</h3><p>示例文件按文档、表格、图纸、代码、图片等类型分组，方便快速定位和回归。</p></article></div></div></section><section class="doc-section doc-section-muted"><div class="doc-section-heading"><span>Why It Works</span><h2>为业务系统准备的工程取舍</h2><p>它不是一个只展示单一 PDF 的小组件，而是一套面向附件中心、OA、知识库和工单系统的前端预览方案。</p></div><div class="doc-value-grid"><article class="doc-card"><h3>少一条服务端链路</h3><p>大多数格式直接在浏览器完成解析，不需要把附件交给后端转 PDF，也减少临时文件和队列任务。</p></article><article class="doc-card"><h3>格式覆盖贴近业务</h3><p>除了 Office、PDF 和图片，也补齐 OFD、DXF、Markdown、代码、日志、配置文件和 MP4。</p></article><article class="doc-card"><h3>阅读质感有兜底</h3><p>Word 保留白色纸张和灰色页面底，PDF 具备缩放、页码、导航窗格和宽度自适应。</p></article><article class="doc-card"><h3>接入边界清晰</h3><p>Vue3、Vue2.7 和 iframe 都有明确示例，URL、File、Blob 转 File 等输入路径也已写明。</p></article><article class="doc-card"><h3>成品可直接下载</h3><p>公开仓库提供混淆压缩库产物、Demo 静态站点、文档静态站点、样例文件和 tarball。</p></article><article class="doc-card"><h3>版本交付可追踪</h3><p>README、文档站、Demo、npm 包和公开成品仓库同步维护，便于验收和分发。</p></article></div></section><section class="doc-section"><div class="doc-section-heading"><span>Choose Your Path</span><h2>按你的接入场景开始</h2><p>先选路线，再进入对应文档。每条路线都给出最短示例和真实项目里的注意事项。</p></div><div class="doc-path-grid"><a class="doc-path-card" href="/guide/quickstart-vue3"><strong>Vue 3 项目</strong><span>安装 @flyfish-group/file-viewer3@1.0.7，使用 createApp(App).use(FileViewer)。</span></a><a class="doc-path-card" href="/guide/quickstart-vue2"><strong>Vue2.7 项目</strong><span>安装 @flyfish-group/file-viewer@1.0.7，使用 Vue.use(FileViewer)。</span></a><a class="doc-path-card" href="/guide/iframe"><strong>多系统复用</strong><span>独立部署预览器，通过 URL 或 postMessage 推送二进制文件。</span></a><a class="doc-path-card" href="/guide/distribution"><strong>成品与二开</strong><span>下载公开产物，或前往官方渠道开通源码和商业二开。</span></a></div></section><section class="doc-final-band"><div><span>Official Resources</span><h2>一个站点承担主页、文档和交付说明</h2><p> 官方文档是 <a href="https://doc.flyfish.dev">doc.flyfish.dev</a>， 在线预览是 <a href="https://viewer.flyfish.dev">viewer.flyfish.dev</a>， 公开成品仓库是 <a href="https://github.com/flyfish-dev/file-viewer">github.com/flyfish-dev/file-viewer</a>。 </p></div><a class="doc-action doc-action-primary" href="/guide/">进入文档导览</a></section></main>',1)])])}const g=s(r,[["render",o]]);export{m as __pageData,g as default};
